toolCalls.args:
{"command": "# Use readelf to get the symbol table and find functions containing the addresses
readelf -sW /tmp/libmonosgen-2.0.so.dbg 2>/dev/null | awk '
$4 == "FUNC" {
    addr = strtonum("0x"$2)
    size = strtonum($3)
    name = $8
    if (addr <= 0x2f4b20 && (addr + size) > 0x2f4b20) printf "0x2f4b20 is in: %s (0x%x + %d)\n", name, addr, size
    if (addr <= 0x2f4c84 && (addr + size) > 0x2f4c84) printf "0x2f4c84 is in: %s (0x%x + %d)\n", name, addr, size
}'", "description": "Find functions containing SGen addresses via readelf", "initial_wait": 30}

{"command": "# Check symbol sizes with nm -S for function range info
nm -S /tmp/libmonosgen-2.0.so.dbg 2>/dev/null | awk '
NF >= 4 && ($3 == "T" || $3 == "t") {
    addr = strtonum("0x"$1)
    size = strtonum("0x"$2)
    name = $4
    if (addr <= 0x2f4b20 && (addr + size) > 0x2f4b20) printf "0x2f4b20 in: %s @ 0x%x size=0x%x\n", name, addr, size
    if (addr <= 0x2f4c84 && (addr + size) > 0x2f4c84) printf "0x2f4c84 in: %s @ 0x%x size=0x%x\n", name, addr, size
}'", "description": "Find enclosing functions with sizes", "initial_wait": 30}
